{{ config(materialized='table') }} --skip_qa --apply_gcp  SELECT     o.id AS "Id",     COALESCE(TRIM(o.name), 'Unknown Opportunity') AS "Name",     CASE LOWER(TRIM(o.stagename))         WHEN 'prospecting' THEN 'Prospecting'         WHEN 'qualification' THEN 'Qualification'         WHEN 'needs analysis' THEN 'Needs Analysis'         WHEN 'value proposition' THEN 'Value Proposition'         WHEN 'id. decision makers' THEN 'Id. Decision Makers'         WHEN 'perception analysis' THEN 'Perception Analysis'         WHEN 'proposal/price quote' THEN 'Proposal/Price Quote'         WHEN 'negotiation/review' THEN 'Negotiation/Review'         WHEN 'closed won' THEN 'Closed Won'         WHEN 'closed lost' THEN 'Closed Lost'         ELSE 'Prospecting'     END AS "StageName",     CASE         WHEN o.closedate ~ '^\d{4}-\d{2}-\d{2}$' THEN TO_CHAR(TO_DATE(o.closedate, 'YYYY-MM-DD'), 'YYYY-MM-DD')         WHEN o.closedate ~ '^\d{2}\.\d{2}\.\d{4}$' THEN TO_CHAR(TO_DATE(o.closedate, 'DD.MM.YYYY'), 'YYYY-MM-DD')         WHEN o.closedate ~ '^\d{2}/\d{2}/\d{4}$' THEN TO_CHAR(TO_DATE(o.closedate, 'MM/DD/YYYY'), 'YYYY-MM-DD')         ELSE '1900-01-01'     END AS "CloseDate",     CASE         WHEN TRIM(o.amount) = '' THEN NULL         ELSE CAST(REPLACE(REPLACE(REPLACE(CASE             WHEN TRIM(o.amount) LIKE '%.%,%' THEN REPLACE(TRIM(o.amount), '.', '')             WHEN TRIM(o.amount) LIKE '%,%.%' THEN REPLACE(TRIM(o.amount), ',', '')             ELSE TRIM(o.amount)         END, ',', '.'), '$', ''), '€', '') AS DOUBLE PRECISION)     END AS "Amount",     TRIM(o.currencyisocode) AS "CurrencyIsoCode",     o.accountid AS "AccountId",     o.id AS "Legacy_Opportunity_ID__c",     NULL AS "CreatedDate",     NULL AS "LastModifiedDate",     0 AS "IsDeleted" FROM     {{ source('fixture_messy_data_v2_src', 'opportunity') }} AS o